// ── Hooks ─────────────────────────────────────────────────────────────────────
function useIntersection(ref) {
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    if (!ref.current) return;
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setVisible(true); obs.disconnect(); }
    });
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return visible;
}

// ── Product Card ──────────────────────────────────────────────────────────────
function ProductCard({ product, onAddToCart }) {
  const ref = useRef();
  const vis = useIntersection(ref);
  return (
    <div ref={ref} className={`product-card${vis ? " fade-in" : ""}`} style={{ opacity: vis ? 1 : 0 }}>
      <div className="product-image">
        <img src={product.image} alt={product.name} />
        {product.badge && <span className="product-badge">{product.badge}</span>}
      </div>
      <div className="product-content">
        <div className="product-category">{product.category}</div>
        <h3 className="product-name">{product.name}</h3>
        <div className="product-price">
          <span className="product-price-current">\₹{product.price.toLocaleString()}</span>
          <span className="product-price-original">\₹{product.original.toLocaleString()}</span>
          <span className="product-discount">-{product.discount}%</span>
        </div>
        <button className="btn btn-primary product-btn" onClick={() => onAddToCart(product)}>Add to Cart</button>
      </div>
    </div>
  );
}

// ── Benefit Item ──────────────────────────────────────────────────────────────
function BenefitItem({ benefit }) {
  const ref = useRef();
  const vis = useIntersection(ref);
  return (
    <div ref={ref} className={`benefit-item${vis ? " fade-in" : ""}`} style={{ opacity: vis ? 1 : 0 }}>
      <div className="benefit-icon">✓</div>
      <div className="benefit-text">
        <h4>{benefit.title}</h4>
        <p>{benefit.desc}</p>
      </div>
    </div>
  );
}

// ── Cart Drawer ───────────────────────────────────────────────────────────────
function CartDrawer({ cart, onClose, onUpdate, onRemove }) {
  const total = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const [checked, setChecked] = useState(false);
  return (
    <>
      <div className="cart-overlay" onClick={onClose} />
      <div className="cart-drawer">
        <div className="cart-header">
          <h3>🛒 Your Cart ({cart.reduce((s, i) => s + i.qty, 0)})</h3>
          <button className="cart-close" onClick={onClose}>✕</button>
        </div>
        <div className="cart-items">
          {cart.length === 0 ? (
            <div className="cart-empty"><div>🛒</div><p>Your cart is empty</p></div>
          ) : cart.map(item => (
            <div className="cart-item" key={item.id}>
              <div className="cart-item-img"><img src={item.image} alt={item.name} /></div>
              <div className="cart-item-info">
                <div className="cart-item-name">{item.name}</div>
                <div className="cart-item-price">\₹{(item.price * item.qty).toLocaleString()}</div>
                <div className="cart-item-qty">
                  <button className="qty-btn" onClick={() => onUpdate(item.id, -1)}>−</button>
                  <span className="qty-num">{item.qty}</span>
                  <button className="qty-btn" onClick={() => onUpdate(item.id, 1)}>+</button>
                  <button className="cart-remove" onClick={() => onRemove(item.id)}>Remove</button>
                </div>
              </div>
            </div>
          ))}
        </div>
        {cart.length > 0 && (
          <div className="cart-footer">
            <div className="cart-total"><span>Total</span><span>\₹{total.toLocaleString()}</span></div>
            {checked ? (
              <div style={{ textAlign:"center", padding:"16px", color:"var(--teal)", fontWeight:700 }}>
                ✅ Order placed! We'll be in touch soon.
              </div>
            ) : (
              <button className="btn btn-primary checkout-btn" onClick={() => setChecked(true)}>Checkout →</button>
            )}
          </div>
        )}
      </div>
    </>
  );
}

// ── Search Modal ──────────────────────────────────────────────────────────────
function SearchModal({ onClose, onAddToCart }) {
  const [q, setQ] = useState("");
  const results = q.length > 1
    ? PRODUCTS.filter(p => p.name.toLowerCase().includes(q.toLowerCase()) || p.category.toLowerCase().includes(q.toLowerCase()))
    : [];
  useEffect(() => {
    const h = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", h);
    return () => window.removeEventListener("keydown", h);
  }, []);
  return (
    <div className="search-overlay" onClick={onClose}>
      <div className="search-box" onClick={e => e.stopPropagation()}>
        <div className="search-input-wrap">
          <span>🔍</span>
          <input autoFocus className="search-input" placeholder="Search products…"
            value={q} onChange={e => setQ(e.target.value)} />
          <button className="btn btn-secondary btn-sm" onClick={onClose}>Close</button>
        </div>
        {q.length > 1 && (
          <div className="search-results">
            {results.length === 0 ? (
              <div className="search-no-results">No products found for "{q}"</div>
            ) : results.map(p => (
              <div className="search-result-item" key={p.id} onClick={() => { onAddToCart(p); onClose(); }}>
                <div className="search-result-img"><img src={p.image} alt={p.name} /></div>
                <div>
                  <div style={{ fontWeight:600, color:"var(--navy)", fontSize:".95rem" }}>{p.name}</div>
                  <div style={{ fontSize:".85rem", color:"var(--gray-500)" }}>
                    {p.category} · \u20B9{p.price.toLocaleString()}
                  </div>
                </div>
                <button className="btn btn-sm btn-primary" style={{ marginLeft:"auto" }}>+ Cart</button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────────
export default function PosturifyStore() {
  const [cart, setCart] = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [toast, setToast] = useState(null);
  const [form, setForm] = useState({ name:"", email:"", phone:"", message:"" });
  const [formSent, setFormSent] = useState(false);

  useEffect(() => {
    const style = document.createElement("style");
    style.textContent = CSS;
    document.head.appendChild(style);
    return () => document.head.removeChild(style);
  }, []);

  useEffect(() => {
    if (!toast) return;
    const t = setTimeout(() => setToast(null), 2500);
    return () => clearTimeout(t);
  }, [toast]);

  const addToCart = (product) => {
    setCart(prev => {
      const ex = prev.find(i => i.id === product.id);
      if (ex) return prev.map(i => i.id === product.id ? { ...i, qty: i.qty + 1 } : i);
      return [...prev, { ...product, qty: 1 }];
    });
    setToast(`✅ ${product.name} added to cart`);
  };

  const updateQty = (id, delta) =>
    setCart(prev => prev.map(i => i.id === id ? { ...i, qty: Math.max(1, i.qty + delta) } : i));

  const removeItem = (id) => setCart(prev => prev.filter(i => i.id !== id));
  const cartCount = cart.reduce((s, i) => s + i.qty, 0);

  const scrollTo = (id) =>
    document.getElementById(id)?.scrollIntoView({ behavior:"smooth", block:"start" });

  const handleFormChange = (e) => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleSubmit = () => {
    if (!form.name || !form.email || !form.message) {
      setToast("⚠️ Please fill in all required fields"); return;
    }
    setFormSent(true);
    setForm({ name:"", email:"", phone:"", message:"" });
    setToast("✅ Message sent! We'll respond within 24 hours.");
  };

  return (
    <div>
      {/* Announcement */}
      <div className="announcement-bar">
        <p>✨ Good Posture. Better You. — Free shipping on orders above ₹999</p>
      </div>

      {/* Header */}
      <header>
        <div className="container">
          <div className="header-content">
            <button className="logo" onClick={() => window.scrollTo({ top:0, behavior:"smooth" })}>
              <img className="logo-img" src={LOGO_SRC} alt="Posturify" />
            </button>
            <nav>
              <a onClick={() => scrollTo("featured")}>Products</a>
              <a onClick={() => scrollTo("about")}>About</a>
              <a onClick={() => scrollTo("contact")}>Contact</a>
            </nav>
            <div className="nav-right">
              <button className="nav-icon" onClick={() => setSearchOpen(true)}>🔍</button>
              <button className="nav-icon">👤</button>
              <button className="nav-icon" onClick={() => setCartOpen(true)} style={{ position:"relative" }}>
                🛒
                {cartCount > 0 && <span className="cart-badge">{cartCount}</span>}
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Hero */}
      <section className="hero">
        <div className="container">
          <div className="hero-grid">
            <div className="hero-content">
              <h1>Premium Posture &amp; Wellness Solutions</h1>
              <p>Trusted quality products designed to improve your posture, support your comfort, and enhance your daily wellness journey. Built on principles of excellence and customer care.</p>
              <div className="hero-cta-buttons">
                <button className="btn btn-primary btn-lg" onClick={() => scrollTo("featured")}>Shop Now</button>
                <button className="btn btn-secondary btn-lg" onClick={() => scrollTo("about")}>Learn More</button>
              </div>
            </div>
            <div className="/hero-image">
              <img src="/slider.png" alt="Posture Support" />
            </div>
          </div>
        </div>
      </section>

      {/* Featured Products */}
      <section className="section light-bg" id="featured">
        <div className="container">
          <div className="section-header">
            <h2>Featured Products</h2>
            <p>Carefully curated solutions designed for comfort, quality, and real results you can trust.</p>
          </div>
          <div className="product-grid">
            {PRODUCTS.map(p => (
              <ProductCard key={p.id} product={p} onAddToCart={addToCart} />
            ))}
          </div>
        </div>
      </section>

      {/* About */}
      <section className="section" id="about">
        <div className="container">
          <div className="about-grid">
            <div className="about-content">
              <h2>Why Choose Posturify?</h2>
              <p>We believe that wellness shouldn't be complicated. Our mission is to provide premium-quality health and posture solutions that actually work, backed by research and customer trust.</p>
              <p>Every product is carefully selected and tested to ensure it meets our high standards for quality, comfort, and effectiveness.</p>
              {BENEFITS.map(b => <BenefitItem key={b.title} benefit={b} />)}
            </div>
            <div className="about-logo-box">
              <img src={LOGO_SRC} alt="Posturify Logo" />
            </div>
          </div>
        </div>
      </section>

      {/* Contact */}
      <section className="section contact-section" id="contact">
        <div className="container">
          <div className="contact-content">
            <h2>Get in Touch</h2>
            <p>Have questions? We're here to help. Reach out and we'll respond within 24 hours.</p>
          </div>
          <div className="contact-form">
            <div className="form-group">
              <label>Your Name</label>
              <input type="text" name="name" placeholder="John Doe" value={form.name} onChange={handleFormChange} />
            </div>
            <div className="form-group">
              <label>Email Address</label>
              <input type="email" name="email" placeholder="your@email.com" value={form.email} onChange={handleFormChange} />
            </div>
            <div className="form-group">
              <label>Phone Number</label>
              <input type="tel" name="phone" placeholder="+91 (555) 000-0000" value={form.phone} onChange={handleFormChange} />
            </div>
            <div className="form-group">
              <label>Your Message</label>
              <textarea name="message" placeholder="Tell us how we can help..." value={form.message} onChange={handleFormChange} />
            </div>
            {formSent ? (
              <div className="form-success">✅ Thank you! We'll get back to you shortly.</div>
            ) : (
              <button type="button" className="btn btn-primary btn-lg"
                style={{ width:"100%", justifyContent:"center" }} onClick={handleSubmit}>
                Send Message
              </button>
            )}
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer>
        <div className="container">
          <div className="footer-grid">
            <div className="footer-section">
              <h4>About Us</h4>
              <p style={{ margin:0, color:"var(--gray-400)", fontSize:".95rem" }}>
                Posturify is dedicated to providing premium wellness solutions and posture support products.
                Good Posture. Better You.
              </p>
            </div>
            <div className="footer-section">
              <h4>Quick Links</h4>
              <ul>
                {["Products","About","Contact","Blog"].map(l => (
                  <li key={l}><a onClick={() => l !== "Blog" && scrollTo(l.toLowerCase())}>{l}</a></li>
                ))}
              </ul>
            </div>
            <div className="footer-section">
              <h4>Customer Care</h4>
              <ul>
                {["Contact Us","Returns & Refunds","Shipping Info","FAQ"].map(l => (
                  <li key={l}><a onClick={() => scrollTo("contact")}>{l}</a></li>
                ))}
              </ul>
            </div>
            <div className="footer-section">
              <h4>Legal</h4>
              <ul>
                {["Privacy Policy","Terms of Service","Cookies","Disclaimer"].map(l => (
                  <li key={l}><a>{l}</a></li>
                ))}
              </ul>
            </div>
          </div>
          <div className="footer-bottom">
            <p>© 2024 Posturify. All rights reserved.</p>
            <div className="footer-social">
              <a>Facebook</a>
              <a>Instagram</a>
              <a>Twitter</a>
            </div>
          </div>
        </div>
      </footer>

      {cartOpen && (
        <CartDrawer cart={cart} onClose={() => setCartOpen(false)}
          onUpdate={updateQty} onRemove={removeItem} />
      )}
      {searchOpen && (
        <SearchModal onClose={() => setSearchOpen(false)} onAddToCart={addToCart} />
      )}
      {toast && <div className="toast">{toast}</div>}
    </div>
  );
}
